import React from 'react';

const PropertyCard = ({ property }) => {
  return (
    <div className="w-[180px] md:w-[260px] bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-xl transition-all duration-500 group">
      {/* Imagen con zoom al pasar el mouse */}
      <div className="h-32 md:h-44 w-full overflow-hidden relative">
        <img 
          src={property.mainImage} 
          alt={property.title} 
          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
          onError={(e) => { e.target.src = "https://via.placeholder.com/400x300?text=Propiedad"; }}
        />
        <div className="absolute top-2 left-2 bg-white/90 backdrop-blur-sm text-blue-700 text-[9px] font-bold px-2 py-1 rounded-full shadow-sm">
          {property.tags[0]}
        </div>
      </div>

      {/* Contenido de la Ficha */}
      <div className="p-4">
        <h3 className="text-sm md:text-base font-semibold text-slate-800 leading-tight mb-1 truncate">
          {property.title}
        </h3>
        <p className="text-blue-600 font-bold text-base md:text-lg mb-3">
          {property.price}
        </p>
        
        {/* Iconos Modernos y Minimalistas */}
        <div className="flex justify-between text-slate-400 text-[10px] md:text-xs mb-4 border-t border-slate-50 pt-3">
          <span className="flex items-center gap-1 font-medium">
            <span className="opacity-70">◈</span> {property.beds} Hab.
          </span>
          <span className="flex items-center gap-1 font-medium">
            <span className="opacity-70">◈</span> {property.area}
          </span>
        </div>

        {/* Botón Aesthetic */}
        <button className="w-full bg-slate-50 hover:bg-blue-600 text-slate-600 hover:text-white text-[10px] md:text-xs font-bold py-2.5 rounded-xl transition-all duration-300 border border-slate-100 hover:border-blue-600 uppercase tracking-wider">
          Ver Detalles
        </button>
      </div>
    </div>
  );
};

export default PropertyCard;
